from abc import ABC, abstractmethod
from typing import Generator, Dict, Any, Optional, List
import logging
from datetime import datetime
import time

logger = logging.getLogger(__name__)


class BaseExtractor(ABC):
    def __init__(self, config: Dict[str, Any]):
        self.config = config
        self.rate_limit_delay = config.get('rate_limit_delay', 0.1)
        self.batch_size = config.get('batch_size', 100)
        self.max_retries = config.get('max_retries', 3)
        self.last_sync_time: Optional[datetime] = None

    @abstractmethod
    def extract(self, **kwargs) -> Generator[List[Dict[str, Any]], None, None]:
        pass

    @abstractmethod
    def get_schema(self) -> Dict[str, Any]:
        pass

    @abstractmethod
    def validate_config(self) -> bool:
        pass

    def handle_rate_limit(self, retry_after: Optional[int] = None):
        if retry_after:
            logger.info(f"Rate limited. Waiting {retry_after} seconds...")
            time.sleep(retry_after)
        else:
            time.sleep(self.rate_limit_delay)

    def retry_with_backoff(self, func, *args, **kwargs):
        for attempt in range(self.max_retries):
            try:
                return func(*args, **kwargs)
            except Exception as e:
                if attempt == self.max_retries - 1:
                    raise
                wait_time = (2 ** attempt) * 2
                logger.warning(f"Attempt {attempt + 1} failed: {e}. Retrying in {wait_time}s...")
                time.sleep(wait_time)

    def get_incremental_filter(self, last_modified_field: str, last_sync: datetime) -> Dict[str, Any]:
        return {
            'filterGroups': [{
                'filters': [{
                    'propertyName': last_modified_field,
                    'operator': 'GT', 
                    'value': int(last_sync.timestamp() * 1000)
                }]
            }]
        }

