import requests
from typing import Generator, Dict, Any, List, Optional
import logging
from datetime import datetime
from ..core.base_extractor import BaseExtractor

logger = logging.getLogger(__name__)


class HubSpotExtractor(BaseExtractor):
    BASE_URL = "https://api.hubapi.com"

    OBJECT_SCHEMAS = {
        'contacts': {
            'properties': [
                'firstname', 'lastname', 'email', 'company', 'phone',
                'createdate', 'lastmodifieddate', 'lifecyclestage',
                'hs_lead_status', 'hubspot_owner_id'
            ],
            'id_field': 'id',
            'modified_field': 'lastmodifieddate'
        },
        'companies': {
            'properties': [
                'name', 'domain', 'industry', 'numberofemployees',
                'annualrevenue', 'createdate', 'hs_lastmodifieddate',
                'lifecyclestage', 'hubspot_owner_id'
            ],
            'id_field': 'id',
            'modified_field': 'hs_lastmodifieddate'
        },
        'deals': {
            'properties': [
                'dealname', 'amount', 'closedate', 'dealstage',
                'pipeline', 'createdate', 'hs_lastmodifieddate',
                'hubspot_owner_id', 'hs_forecast_probability'
            ],
            'id_field': 'id',
            'modified_field': 'hs_lastmodifieddate'
        },
        'engagements': {
            'properties': [],
            'id_field': 'id', 
            'modified_field': 'lastUpdated'
        },
        'tickets': {
            'properties': [
                'subject', 'content', 'hs_pipeline', 'hs_pipeline_stage',
                'hs_ticket_priority', 'createdate', 'hs_lastmodifieddate',
                'hubspot_owner_id'
            ],
            'id_field': 'id',
            'modified_field': 'hs_lastmodifieddate'
        }
    }

    def __init__(self, config: Dict[str, Any]):
        super().__init__(config)
        self.api_key = config.get('api_key') or config.get('access_token')
        self.headers = self._get_headers()

    def _get_headers(self) -> Dict[str, str]:
        if self.api_key:
            if self.api_key.startswith('pat-'):
                return {'Authorization': f'Bearer {self.api_key}'}
            else:
                return {'hapikey': self.api_key}
        raise ValueError("No API key or access token provided")

    def validate_config(self) -> bool:
        if not self.api_key:
            raise ValueError("HubSpot API key or access token required")

        try:
            response = requests.get(
                f"{self.BASE_URL}/crm/v3/objects/contacts?limit=1",
                headers=self.headers
            )
            response.raise_for_status()
            return True
        except requests.exceptions.RequestException as e:
            logger.error(f"Failed to validate HubSpot config: {e}")
            return False

    def get_schema(self, object_type: str = None) -> Dict[str, Any]:
        if object_type:
            return self.OBJECT_SCHEMAS.get(object_type, {})
        return self.OBJECT_SCHEMAS

    def extract(
        self, 
        object_type: str,
        properties: Optional[List[str]] = None,
        incremental: bool = True,
        last_sync: Optional[datetime] = None,
        associations: Optional[List[str]] = None,
        **kwargs
    ) -> Generator[List[Dict[str, Any]], None, None]:

        if object_type not in self.OBJECT_SCHEMAS:
            raise ValueError(f"Unsupported object type: {object_type}")

        schema = self.OBJECT_SCHEMAS[object_type]

        if not properties:
            properties = schema['properties']

        if object_type == 'engagements':
            yield from self._extract_engagements(**kwargs)
            return

        params = {
            'limit': self.batch_size,
            'properties': ','.join(properties) if properties else None,
            'associations': ','.join(associations) if associations else None
        }

        if incremental and last_sync:
            modified_field = schema['modified_field']
            params['filterGroups'] = [{
                'filters': [{
                    'propertyName': modified_field,
                    'operator': 'GT',
                    'value': int(last_sync.timestamp() * 1000)
                }]
            }]

        after = None
        total_extracted = 0

        while True:
            if after:
                params['after'] = after

            try:
                response = self.retry_with_backoff(
                    self._make_request,
                    f"/crm/v3/objects/{object_type}",
                    params
                )

                results = response.get('results', [])
                if results:
                    batch = self._normalize_records(results, object_type)
                    yield batch
                    total_extracted += len(batch)
                    logger.info(f"Extracted {len(batch)} {object_type}. Total: {total_extracted}")

                paging = response.get('paging', {})
                after = paging.get('next', {}).get('after')

                if not after:
                    break

                self.handle_rate_limit()

            except Exception as e:
                logger.error(f"Failed to extract {object_type}: {e}")
                raise

        logger.info(f"Extraction complete. Total {object_type} extracted: {total_extracted}")

    def _extract_engagements(self, engagement_type: str = None, **kwargs) -> Generator[List[Dict[str, Any]], None, None]:
        params = {
            'limit': self.batch_size
        }

        if engagement_type:
            params['type'] = engagement_type.upper()

        offset = 0
        total_extracted = 0

        while True:
            params['offset'] = offset

            try:
                response = self.retry_with_backoff(
                    self._make_request,
                    "/engagements/v1/engagements/paged",
                    params
                )

                results = response.get('results', [])
                if results:
                    batch = self._normalize_engagements(results)
                    yield batch
                    total_extracted += len(batch)
                    logger.info(f"Extracted {len(batch)} engagements. Total: {total_extracted}")

                if not response.get('hasMore', False):
                    break

                offset = response.get('offset', offset + self.batch_size)
                self.handle_rate_limit()

            except Exception as e:
                logger.error(f"Failed to extract engagements: {e}")
                raise

        logger.info(f"Extraction complete. Total engagements extracted: {total_extracted}")

    def _make_request(self, endpoint: str, params: Dict[str, Any]) -> Dict[str, Any]:
        url = f"{self.BASE_URL}{endpoint}"

        if 'filterGroups' in params:
            response = requests.post(
                f"{url}/search",
                headers=self.headers,
                json=params
            )
        else:
            response = requests.get(
                url,
                headers=self.headers,
                params=params
            )

        if response.status_code == 429:
            retry_after = response.headers.get('Retry-After')
            self.handle_rate_limit(int(retry_after) if retry_after else 10)
            return self._make_request(endpoint, params)

        response.raise_for_status()
        return response.json()

    def _normalize_records(self, records: List[Dict], object_type: str) -> List[Dict[str, Any]]:
        normalized = []
        schema = self.OBJECT_SCHEMAS[object_type]
        id_field = schema['id_field']

        for record in records:
            normalized_record = {
                f'{object_type}_id': record.get(id_field),
                'extracted_at': datetime.utcnow().isoformat()
            }

            properties = record.get('properties', {})
            for key, value in properties.items():
                normalized_record[key] = value

            associations = record.get('associations', {})
            for assoc_type, assoc_data in associations.items():
                normalized_record[f'{assoc_type}_ids'] = [
                    item['id'] for item in assoc_data.get('results', [])
                ]

            normalized.append(normalized_record)

        return normalized

    def _normalize_engagements(self, engagements: List[Dict]) -> List[Dict[str, Any]]:
        normalized = []

        for engagement in engagements:
            eng = engagement.get('engagement', {})
            normalized_record = {
                'engagement_id': eng.get('id'),
                'type': eng.get('type'),
                'created_at': eng.get('createdAt'),
                'last_updated': eng.get('lastUpdated'),
                'owner_id': eng.get('ownerId'),
                'extracted_at': datetime.utcnow().isoformat()
            }

            metadata = engagement.get('metadata', {})
            for key, value in metadata.items():
                normalized_record[f'metadata_{key}'] = value

            associations = engagement.get('associations', {})
            normalized_record['contact_ids'] = associations.get('contactIds', [])
            normalized_record['company_ids'] = associations.get('companyIds', [])
            normalized_record['deal_ids'] = associations.get('dealIds', [])

            normalized.append(normalized_record)

        return normalized

    def get_custom_properties(self, object_type: str) -> List[Dict[str, Any]]:
        try:
            response = self.retry_with_backoff(
                self._make_request,
                f"/crm/v3/properties/{object_type}",
                {}
            )

            return response.get('results', [])
        except Exception as e:
            logger.error(f"Failed to fetch custom properties for {object_type}: {e}")
            return []

