import os
import yaml
from typing import Dict, Any
import logging

logger = logging.getLogger(__name__)


class ConfigLoader:
    @staticmethod
    def load_config(config_path: str = None) -> Dict[str, Any]:
        if not config_path:
            config_path = os.path.join(
                os.path.dirname(__file__),
                '../configs/config.yaml'
            )

        with open(config_path, 'r') as file:
            config = yaml.safe_load(file)

        config = ConfigLoader._resolve_env_vars(config)

        return config

    @staticmethod
    def _resolve_env_vars(config: Any) -> Any:
        if isinstance(config, dict):
            return {
                key: ConfigLoader._resolve_env_vars(value)
                for key, value in config.items()
            }
        elif isinstance(config, list):
            return [ConfigLoader._resolve_env_vars(item) for item in config]
        elif isinstance(config, str) and config.startswith('${') and config.endswith('}'):
            env_var = config[2:-1]
            value = os.environ.get(env_var)
            if value is None:
                logger.warning(f"Environment variable {env_var} not found")
            return value
        else:
            return config

    @staticmethod
    def get_pipeline_config(pipeline_name: str, config_path: str = None) -> Dict[str, Any]:
        config = ConfigLoader.load_config(config_path)

        pipeline_config = config.get('pipelines', {}).get(pipeline_name)
        if not pipeline_config:
            raise ValueError(f"Pipeline '{pipeline_name}' not found in config")

        extractor_name = pipeline_config.get('extractor')
        loader_name = pipeline_config.get('loader')

        if extractor_name:
            extractor_config = config.get(extractor_name, {})
            pipeline_config['extractor_config'] = extractor_config

        if loader_name:
            loader_config = config.get(loader_name, {})
            pipeline_config['loader_config'] = loader_config

        return pipeline_config

