def test_sales_emails():
    api_key = os.environ.get('HUBSPOT_API_KEY')
    if not api_key:
        print("Error: Set HUBSPOT_API_KEY environment variable")
        sys.exit(1)

    headers = {'Authorization': f'Bearer {api_key}'} if api_key.startswith('pat-') else {'hapikey': api_key}
    base_url = "https://api.hubapi.com"

    print("="*60)
    print("TESTING HUBSPOT SALES EMAIL ENDPOINTS")
    print("="*60)

    # 1. Try CRM v3 emails endpoint
    print("\n1. Testing CRM v3 /objects/emails endpoint...")
    print("-" * 40)

    response = requests.get(
        f"{base_url}/crm/v3/objects/emails",
        headers=headers,
        params={'limit': 2}
    )

    if response.status_code == 200:
        data = response.json()
        emails = data.get('results', [])
        if emails:
            print(f"SUCCESS! Found {len(emails)} emails")
            print("\nFirst email properties:")
            email = emails[0]
            for key, value in email.get('properties', {}).items():
                if key in ['hs_email_text', 'hs_email_html']:
                    print(f"  {key}: <content truncated>")
                else:
                    print(f"  {key}: {value}")

            # Check for associations
            if 'associations' in email:
                print("\nAssociations found:")
                for assoc_type, assoc_data in email['associations'].items():
                    print(f"  {assoc_type}: {len(assoc_data.get('results', []))} items")
        else:
            print("No emails found via this endpoint")
    else:
        print(f"Error {response.status_code}: {response.text[:200]}")

    # 2. Try with search/filter for recent emails
    print("\n2. Testing CRM v3 search for emails in last 30 days...")
    print("-" * 40)

    thirty_days_ago = int((datetime.now().timestamp() - 30*24*60*60) * 1000)

    search_body = {
        "filterGroups": [{
            "filters": [{
                "propertyName": "hs_createdate",
                "operator": "GT",
                "value": str(thirty_days_ago)
            }]
        }],
        "limit": 5
    }

    response = requests.post(
        f"{base_url}/crm/v3/objects/emails/search",
        headers=headers,
        json=search_body
    )

    if response.status_code == 200:
        data = response.json()
        emails = data.get('results', [])
        if emails:
            print(f"Found {len(emails)} recent emails")

            # Look for Unify patterns
            print("\nChecking for Unify/Custom patterns:")
            for email in emails:
                props = email.get('properties', {})
                sender = props.get('hs_email_sender_email', '')
                subject = props.get('hs_email_subject', '')
                direction = props.get('hs_email_direction', '')
                status = props.get('hs_email_status', '')

                print(f"\n  Email ID: {email.get('id')}")
                print(f"    From: {sender}")
                print(f"    Subject: {subject[:50]}...")
                print(f"    Direction: {direction}")
                print(f"    Status: {status}")

                # Look for any custom properties that might indicate Unify
                for key, value in props.items():
                    if 'unify' in key.lower() or 'template' in key.lower() or 'campaign' in key.lower():
                        print(f"    POTENTIAL INDICATOR - {key}: {value}")
    else:
        print(f"Error {response.status_code}: {response.text[:200]}")

    # 3. Try legacy engagements API
    print("\n3. Testing Legacy Engagements v1 API...")
    print("-" * 40)

    response = requests.get(
        f"{base_url}/engagements/v1/engagements/paged",
        headers=headers,
        params={'limit': 2, 'type': 'EMAIL'}
    )

    if response.status_code == 200:
        data = response.json()
        engagements = data.get('results', [])
        if engagements:
            print(f"Found {len(engagements)} email engagements")
            engagement = engagements[0]

            print("\nFirst engagement details:")
            eng_data = engagement.get('engagement', {})
            print(f"  Type: {eng_data.get('type')}")
            print(f"  Created: {datetime.fromtimestamp(eng_data.get('createdAt', 0)/1000)}")
            print(f"  Owner ID: {eng_data.get('ownerId')}")

            metadata = engagement.get('metadata', {})
            print("\nMetadata fields:")
            for key, value in metadata.items():
                if key in ['html', 'text']:
                    print(f"  {key}: <content present>")
                else:
                    print(f"  {key}: {value}")
    else:
        print(f"Error {response.status_code}: {response.text[:200]}")

    # 4. Get associated emails for a recent contact
    print("\n4. Testing emails associated with contacts...")
    print("-" * 40)

    # First get a contact
    response = requests.get(
        f"{base_url}/crm/v3/objects/contacts",
        headers=headers,
        params={'limit': 1}
    )

    if response.status_code == 200:
        contacts = response.json().get('results', [])
        if contacts:
            contact_id = contacts[0]['id']
            print(f"Using contact ID: {contact_id}")

            # Get emails associated with this contact
            response = requests.get(
                f"{base_url}/crm/v3/objects/contacts/{contact_id}/associations/emails",
                headers=headers
            )

            if response.status_code == 200:
                data = response.json()
                email_associations = data.get('results', [])
                print(f"Found {len(email_associations)} associated emails")

                if email_associations:
                    # Get details of first associated email
                    email_id = email_associations[0]['id']
                    response = requests.get(
                        f"{base_url}/crm/v3/objects/emails/{email_id}",
                        headers=headers,
                        params={'properties': 'hs_email_subject,hs_email_sender_email,hs_email_direction,hs_email_status'}
                    )

                    if response.status_code == 200:
                        email = response.json()
                        print("\nAssociated email details:")
                        for key, value in email.get('properties', {}).items():
                            print(f"  {key}: {value}")

