            raise ValueError(f"Unsupported extractor: {extractor_type}")

        if loader_type == 'redshift':
            self.loader = RedshiftLoader(self.config['loader_config'])
        else:
            raise ValueError(f"Unsupported loader: {loader_type}")

    def run(self, full_refresh: bool = False):
        logger.info(f"Starting pipeline: {self.pipeline_name}")
        start_time = datetime.utcnow()

        try:
            self.initialize_components()

            if not self.extractor.validate_config():
                raise ValueError("Extractor configuration validation failed")

            table_name = self.config.get('table_name')
            mode = self.config.get('mode', 'append')

            last_sync = None
            if self.config.get('incremental', True) and not full_refresh:
                last_sync = self.loader.get_last_sync_time(table_name)
                if last_sync:
                    logger.info(f"Running incremental sync from {last_sync}")
                else:
                    logger.info("No previous sync found, running full sync")

            # Get schema from extractor if it provides one
            if hasattr(self.extractor, 'get_schema'):
                schema = self.extractor.get_schema()
            else:
                # Fallback to config-based schema
                object_type = self.config.get('object_type')
                properties = self.config.get('properties')
                associations = self.config.get('associations')
                schema = self._build_schema(properties, associations)

            self.loader.create_table_if_not_exists(
                table_name,
                schema,
                drop_if_exists=full_refresh
            )

            total_records = 0

            # Extract data based on extractor type
            extract_kwargs = {
                'incremental': not full_refresh,
                'last_sync': last_sync
            }

            # Add config-specific parameters if they exist
            for key in ['object_type', 'properties', 'associations', 'engagement_type']:
                if key in self.config:
                    extract_kwargs[key] = self.config[key]

            for batch in self.extractor.extract(**extract_kwargs):
                success = self.loader.load(
                    data=batch,
                    table_name=table_name,
                    mode=mode,
                    primary_keys=self.config.get('primary_keys', ['id']),
                    use_s3=self.config.get('use_s3', True)
                )

                if not success:
                    raise Exception("Failed to load batch")

                total_records += len(batch)
                logger.info(f"Loaded batch of {len(batch)} records. Total: {total_records}")

            self.loader.analyze_table(table_name)

            duration = (datetime.utcnow() - start_time).total_seconds()
            logger.info(
                f"Pipeline completed successfully. "
                f"Total records: {total_records}, Duration: {duration:.2f}s"
            )

        except Exception as e:
            logger.error(f"Pipeline failed: {e}")
            raise
        finally:
            if self.loader:
                self.loader.close()

    def _build_schema(self, properties: list, associations: list) -> dict:
        schema = {}

        object_type = self.config.get('object_type')
        schema[f'{object_type}_id'] = {'type': 'string', 'nullable': False}

        if properties:
            for prop in properties:
                schema[prop] = {'type': 'string', 'nullable': True}

        if associations:
            for assoc in associations:
                schema[f'{assoc}_ids'] = {'type': 'array', 'nullable': True}

        if object_type in ['contacts', 'companies', 'deals']:
            schema['_sortkeys'] = ['lastmodifieddate', f'{object_type}_id']
            schema['_distkey'] = f'{object_type}_id'

        return schema


def main():
    parser = argparse.ArgumentParser(description='Run data pipeline')
    parser.add_argument('pipeline', help='Pipeline name from config')
    parser.add_argument('--config', required=True, 
                       help='Config file name (e.g., hubspot_emails)')
    parser.add_argument('--full-refresh', action='store_true', 
                       help='Run full refresh instead of incremental')

    args = parser.parse_args()

    try:
        runner = PipelineRunner(args.pipeline, args.config)
        runner.run(full_refresh=args.full_refresh)
    except Exception as e:
        logger.error(f"Pipeline execution failed: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()

